func GetDocProvider() DocProvider {
	provider := make(DocProvider)

	for _, fn := range docProviderFuncs {
		p := fn()
		for k, v := range p {
			if _, found := provider[k]; found {

				panic(fmt.Sprintf("Duplicate doc provider key: %q", k))
			}
			provider[k] = v
		}
	}

	return provider
}
